// // This module captures the value of the data input (d) on the falling edge of the clock (clk) and resets the output (q) to 1 when the reset signal (rst) is deasserted.
module d_flip_flop(
  input clk,
  input rst,
  input d,
  output reg q
);

  always @(posedge clk or posedge rst) begin
    if (rst)
      q <= 1'b0;
    else
      q <= d;
  end

endmodule
